// Node.js example using opossum
const CircuitBreaker = require('opossum')

async function fetchUser(id) {
  // remote call, e.g. fetch(`https://api.example.com/users/${id}`)
}

const options = { timeout: 3000, errorThresholdPercentage: 50, resetTimeout: 10000 }
const breaker = new CircuitBreaker(fetchUser, options)

breaker.fallback(() => ({ id: null, name: 'Service unavailable' }))

breaker.on('open', () => console.warn('circuit open'))
breaker.on('halfOpen', () => console.info('circuit half-open'))
breaker.on('close', () => console.info('circuit closed'))

// use breaker.fire(id) instead of directly calling fetchUser
